    def test_otp(self):                 ok("123456", "must be a valid otp code"); fail("12345", "must be a valid otp code")
    def test_totp(self):                ok("987654", "must be a valid totp code"); fail("1234567", "must be a valid totp code")
    def test_no_sql_injection(self):    ok("hello world", "must not contain sql injection"); fail("SELECT * FROM users", "must not contain sql injection")
    def test_no_xss(self):              ok("hello world", "must not contain xss"); fail("<script>alert(1)</script>", "must not contain xss")
    def test_currency_code(self):       ok("EUR", "must be a valid currency code"); fail("XYZ", "must be a valid currency code")
    def test_country_code(self):        ok("FR", "must be a valid country code"); fail("XX", "must be a valid country code")
    def test_language_code(self):       ok("fr", "must be a valid language code"); fail("xx", "must be a valid language code")
    def test_mime_type(self):           ok("image/jpeg", "must be a valid mime type"); fail("jpeg", "must be a valid mime type")
