    def test_http_method(self):         ok("GET", "must be a valid http method"); fail("FETCH", "must be a valid http method")
    def test_port(self):                ok(8080, "must be a valid port number"); fail(99999, "must be a valid port number")
    def test_isbn(self):                ok("978-3-16-148410-0", "must be a valid isbn"); fail("123", "must be a valid isbn")
    def test_iban(self):                ok("FR76AABBCCC", "must be a valid iban"); fail("123", "must be a valid iban")
    def test_pypi_name(self):           ok("livecheck", "must be a valid pypi package name"); fail("My Package!", "must be a valid pypi package name")
